import{_ as e,c as a,o as l,af as i}from"./chunks/framework.DcbXK6Cz.js";const r="/menu-screenshot.jpg",g=JSON.parse('{"title":"功能详解","description":"","frontmatter":{"sidebar":[{"text":"快速开始","link":"/guide/quickstart"},{"text":"功能详解","link":"/guide/menu"},{"text":"插件与扩展","link":"/guide/plugins"},{"text":"常见问题","link":"/faq"},{"text":"关于作者","link":"/about"}]},"headers":[],"relativePath":"guide/menu.md","filePath":"guide/menu.md"}'),n={name:"guide/menu.md"};function d(o,t,s,h,u,c){return l(),a("div",null,t[0]||(t[0]=[i('<h1 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h1><p>SillyTavern-Termux 采用全中文菜单，所有管理操作均可直观完成。</p><h2 id="主菜单结构" tabindex="-1">主菜单结构 <a class="header-anchor" href="#主菜单结构" aria-label="Permalink to &quot;主菜单结构&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">选项</th><th style="text-align:left;">功能说明</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">🚀 启动 SillyTavern 主程序</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">🔄 更新 SillyTavern 最新代码</td></tr><tr><td style="text-align:center;">3</td><td style="text-align:left;">🔧 快速配置（如开启局域网、恢复初始配置）</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">🧩 插件管理（安装/卸载热门插件）</td></tr><tr><td style="text-align:center;">5</td><td style="text-align:left;">🛠️ 系统维护（依赖修复、数据备份/恢复）</td></tr><tr><td style="text-align:center;">6</td><td style="text-align:left;">📦 脚本管理（自检升级、更新日志、彻底卸载）</td></tr><tr><td style="text-align:center;">7</td><td style="text-align:left;">ℹ️ 关于脚本（作者、交流群、邮件、资源获取）</td></tr></tbody></table><hr><h2 id="重点功能一览" tabindex="-1">重点功能一览 <a class="header-anchor" href="#重点功能一览" aria-label="Permalink to &quot;重点功能一览&quot;">​</a></h2><h3 id="启动与更新" tabindex="-1">启动与更新 <a class="header-anchor" href="#启动与更新" aria-label="Permalink to &quot;启动与更新&quot;">​</a></h3><ul><li><strong>启动酒馆</strong>：自动检测依赖，支持脚本修复。</li><li><strong>一键升级</strong>：拉取 SillyTavern 官方最新代码，无需手动操作。</li></ul><h3 id="快速配置" tabindex="-1">快速配置 <a class="header-anchor" href="#快速配置" aria-label="Permalink to &quot;快速配置&quot;">​</a></h3><ul><li>一键开启/关闭局域网监听。</li><li>恢复初始配置（备份与还原 config.yaml）。</li></ul><h3 id="插件管理" tabindex="-1">插件管理 <a class="header-anchor" href="#插件管理" aria-label="Permalink to &quot;插件管理&quot;">​</a></h3><ul><li>支持热门社区插件一键安装与卸载。</li><li>插件详细介绍与安全提示，防范恶意脚本。</li></ul><h3 id="系统维护" tabindex="-1">系统维护 <a class="header-anchor" href="#系统维护" aria-label="Permalink to &quot;系统维护&quot;">​</a></h3><ul><li>一键修复依赖（Node.js、Git、curl 等）。</li><li>数据与本体备份/恢复，自动打包到手机“下载”目录。</li><li>交互式导入，防误操作，防止数据丢失。</li></ul><h3 id="脚本管理" tabindex="-1">脚本管理 <a class="header-anchor" href="#脚本管理" aria-label="Permalink to &quot;脚本管理&quot;">​</a></h3><ul><li>检测并在线升级 Install/Menu 脚本。</li><li>查看详细更新日志。</li><li>一键彻底卸载酒馆及脚本（环境清理）。</li></ul><h3 id="关于与资源" tabindex="-1">关于与资源 <a class="header-anchor" href="#关于与资源" aria-label="Permalink to &quot;关于与资源&quot;">​</a></h3><ul><li>作者信息、QQ群、邮箱支持自动跳转。</li><li>“资源获取”菜单：一键下载安装 Discord，直达五大官方/社区 Discord 频道。</li></ul><hr><h2 id="菜单截图" tabindex="-1">菜单截图 <a class="header-anchor" href="#菜单截图" aria-label="Permalink to &quot;菜单截图&quot;">​</a></h2><p><img src="'+r+'" alt="主菜单界面"></p>',21)]))}const f=e(n,[["render",d]]);export{g as __pageData,f as default};
